span.p:
{
"schemaVersion": 1,
"enabled": true, ＊master＊
"syncMode": "automatic", ＊auto or manual＊
"groupOf": {
"1": "A",
"2": "A",
"4": "B"
},
"spaceNames": { ＊keyed by group letter＊
"A": { "1": "Code", "2": "Email" },
"B": { "1": "Reference" }
},
"_lastSeen": { ＊for stale entries＊
"5": { name, uuid, date }
},
"switchDelay": 0.3,
"debounceSeconds": 0.8,
"popupDuration": 2,
"statusDuration": 3,
"hotkeys": {
"toggle": { mods:[ctrl,alt,cmd], key:"Y" },
"showNames": { mods:[ctrl,alt,cmd], key:"N" },
"renameSpace": { mods:[ctrl,alt,cmd], key:"R" },
"syncNow": { mods:[ctrl,alt,cmd], key:"S" },
"openSettings":{ mods:[ctrl,alt,cmd], key:"," }
}
// v2 forward-compat:
// "groupLabels": { "A": "Code", "B": "Reference" }
}

{
{1, 2},
{4}
}
Derived from groupOf at runtime.
Letters collapse to ordered
position lists for the sync engine.
